var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"도착할 때까지 트렁크에 처박혀 있으라니, 취급이 왜 이래?","JPN":"着くまでトランクに隠れてろだなんて、あんまりなんじゃないか？","ENG":"You want me to stay in the trunk the whole ride over? Are you serious?","TWN":"竟然要我抵達前先待在後車廂裡，為什麼這樣對我？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"조금만 참아. 네 몽타주가 이미 블랙 네트워크에 쫙 깔렸어.","JPN":"もう少し我慢しろ。お前のモンタージュがすでにブラックネットワークに広がっている。","ENG":"Just hang in there. Your picture is already plastered all throughout the Dark Network.","TWN":"你忍耐一下，誰叫你的畫像已經在黑色網路上傳開來。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그리고 이 도시는 그라운드 원이다. 현상금이라면 눈에 불을 켤 용병들이 많지.","JPN":"それにこの都市はグラウンド・ワンだ。懸賞金とあれば目の色が変わる傭兵がたくさんいる。","ENG":"Also, this is Ground One. Mercenaries are always on the lookout for some bounty.","TWN":"再者這裡可是G1，有很多傭兵都在覬覦懸賞金好嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……사례금 챙기는 우리처럼 말이지.","JPN":"……謝礼貰ってる私たちみたいにね。","ENG":"...Just like us.","TWN":"……就像我們會拿報酬一樣嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 복수를 하기 위해서라면 뭐든지 할 수 있어.","JPN":"隊長、復讐のためなら何だってできる。","ENG":"Captain, I'm ready to do anything for revenge.","TWN":"隊長，為了報仇，我什麼都願意做。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하지만, 돈이 엮이게 되는 순간부터는…….","JPN":"でも、金が絡んでくる瞬間からは……","ENG":"But, when money gets involved...","TWN":"但牽扯到金錢的瞬間……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"암을 치료할 수 있었다면, 지훈이 놈이 죽으려고 했을까?","JPN":"癌を治療することができたら、ゴトウは死のうと思っただろうか？","ENG":"Do you think Jihoon would have sacrificed himself if he could treat his cancer?","TWN":"要是可以治療癌症的話，你認為智勳那傢伙還會想死嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지금 그 녀석 얘기가 왜 나와?","JPN":"そこでなんであいつの話が出てくるんだよ。","ENG":"Why are you bringing him up now?","TWN":"現在為何要提到他？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"성냥팔이를 해치운 뒤로 계속 해 왔던 고민이다.","JPN":"マッチ売りとのことがあってからずっと悩んできたことだ。","ENG":"I've been thinking about it ever since we defeated Matchmaker.","TWN":"除掉賣火柴的後，我一直在想這件事。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"내가 그 놈에게 왜 그런 화려한 은퇴식을 치러 줘야 했는지 말이다.","JPN":"なぜ俺はあいつにあんな派手な引退式をしてやるしかなかったのか。","ENG":"You know, why I let him go out with a bang like that.","TWN":"我為何必須要替他辦那麼華麗的退休儀式？"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……분명 그보다 더 나은 결말도 있었을 텐데.","JPN":"……きっとそれよりましな結末もあったはずなのに。","ENG":"...There had to have been a better way.","TWN":"……他明明可以有更好的下場。"},"stage":{"bg":"HIGHWAY_TWILIGHT","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이제 와서 동료애라도 생겼어? 나더러 총알받이 운운할 때는 언제고.","JPN":"今更仲間を惜しむ気持ちが芽生えたってのか？　私を弾除けだって言ったくせに。","ENG":"Did you just develop comradery for your team? You put me through all that human shield crap, too.","TWN":"你現在突然產生同胞愛嗎？之前是誰叫我當砲灰的？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼 애초에 우리가 이 짓을 계속 할 필요는 뭐야?! 각자 살 길 찾으라고 할 것이지!","JPN":"そもそもこの仕事を続ける理由は何だよ！？　各自勝手にやらせておけばいいじゃないか！","ENG":"Then what's the point of us continue doing this?! Why not just tell us to find another occupation?","TWN":"那我們為何要持續做這件事？！打從一開始就各自尋找活路就好啦！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"동료애 같은 말 대신 효율이라고 해라.","JPN":"仲間を惜しむ気持ちじゃなく、効率って言え。","ENG":"It's not about comradery, it's about being efficient.","TWN":"這不是同胞愛，是效率。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"도착하기 전까지 무전기는 끄고 있어. 배터리 방전되면 골치 아파진다.","JPN":"着くまで無線機の電源は切っておけよ。バッテリーがなくなると面倒なことになる。","ENG":"Make sure to turn off your comms until we arrive. It's gonna be a hassle if your battery dies later.","TWN":"抵達前先關掉無線電，萬一沒電的話會很傷腦筋的。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"역시 민우 대장, 앞으로는 무뚝뚝한 척 하면서 사실은 대원들에게 끈끈한 정을 느끼는 거네요.","JPN":"さすがマツダ隊長、人前ではぶっきらぼうなふりをしてても、実は隊員たちに深い情を抱いているんですね。","ENG":"Wow, Captain. You always put on this facade of being indifferent, but you seem to really care about your team.","TWN":"真不愧是民宇隊長，之後你面無表情的時候，我都會感受到你對隊員濃烈的愛。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}}]`);export{e as default};